// Compact a possibly-non-contiguous group-id vector into 0-based contiguous ids
// in first-appearance order, into `out` (size npar). Returns the group count.
std::int32_t compact_groups(const std::vector<std::int32_t>& eq_groups,
                            std::int32_t npar,
                            std::vector<std::int32_t>& out) {
  out.assign(static_cast<std::size_t>(npar < 0 ? 0 : npar), 0);
  const bool have = static_cast<std::int32_t>(eq_groups.size()) == npar;
  std::unordered_map<std::int32_t, std::int32_t> remap;
  std::int32_t next = 0;
  for (std::int32_t k = 0; k < npar; ++k) {
    const std::int32_t raw = have ? eq_groups[static_cast<std::size_t>(k)] : k;
    auto [it, inserted] = remap.try_emplace(raw, next);
    if (inserted) ++next;
    out[static_cast<std::size_t>(k)] = it->second;
  }
  return next;
}

struct DisjointSet {
  std::vector<std::int32_t> parent;
  std::vector<std::int32_t> rank;

  explicit DisjointSet(std::int32_t n)
      : parent(static_cast<std::size_t>(n)),
        rank(static_cast<std::size_t>(n), 0) {
    for (std::int32_t i = 0; i < n; ++i) parent[static_cast<std::size_t>(i)] = i;
  }

  std::int32_t find(std::int32_t x) {
    auto& p = parent[static_cast<std::size_t>(x)];
    if (p != x) p = find(p);
    return p;
  }

  void unite(std::int32_t a, std::int32_t b) {
    a = find(a);
    b = find(b);
    if (a == b) return;
    auto& ra = rank[static_cast<std::size_t>(a)];
    auto& rb = rank[static_cast<std::size_t>(b)];
    if (ra < rb) {
      parent[static_cast<std::size_t>(a)] = b;
    } else if (ra > rb) {
      parent[static_cast<std::size_t>(b)] = a;
    } else {
      parent[static_cast<std::size_t>(b)] = a;
      ++ra;
    }
  }
};

struct ConstraintComponent {
  std::vector<std::int32_t> params;
  std::vector<Eigen::Index> rows;
};

struct ComponentBasis {
  std::vector<std::int32_t> params;
  Eigen::VectorXd theta0;
  Eigen::MatrixXd K;
  Eigen::MatrixXd A;
  Eigen::VectorXd b;
  Eigen::Index n_alpha = 0;
  Eigen::Index rank = 0;
};

double infeasibility_tolerance(const Eigen::MatrixXd& R,
                               const Eigen::VectorXd& d) {
  return 1e-8 * std::max(1.0, d.norm() + R.norm());
}

