post_expected<EqConstraints>
build_eq_constraints(const spec::LatentStructure& pt, bool allow_nonlinear) {
  // Constraint kinds that cannot be reduced to the linear affine
  // reparameterization, classified by lavaanify (`compute_eq_groups` +
  // `resolve_lin_constraints`). Each gets a specific error so the caller
  // knows exactly which kind is unsupported.
  if (pt.has_inequality_constraints) {
    return std::unexpected(err(
        "inequality constraints (`<` / `>`) are not supported: "
        "inequality-constrained estimation needs boundary (chi-bar-squared) "
        "asymptotics that magmaan does not implement"));
  }
  if (!allow_nonlinear && !pt.nonlinear_eq_rows.empty()) {
    return std::unexpected(err(
        "nonlinear equality constraints (e.g. `a == b*c`) are not supported "
        "by this estimator"));
  }
  if (pt.has_unenforced_constraints) {
    return std::unexpected(err(
        "malformed `==` constraint: a side failed to parse or references an "
        "unknown parameter"));
  }

  const std::int32_t npar = pt.n_free();
  EqConstraints out;
  out.npar = npar;
  if (npar <= 0) {
    out.n_alpha = 0; out.rank = 0;
    out.theta0  = Eigen::VectorXd::Zero(0);
    out.Kmat    = Eigen::MatrixXd(0, 0);
    out.A_eq    = Eigen::MatrixXd(0, 0);
    out.b_eq    = Eigen::VectorXd::Zero(0);
    return out;
  }
  const std::size_t P = static_cast<std::size_t>(npar);

  // The merge partition from `eq_groups` (contiguous, first-appearance order).
  std::vector<std::int32_t> group;
  const std::int32_t n_groups = compact_groups(pt.eq_groups, npar, group);

  const std::size_t n_lin = pt.lin_constraint_d.size();   // # general-linear rows

  if (n_lin == 0) {
    // ---- Pure-merge path: bit-identical to the P9-phase-1 representation. ----
    out.group   = std::move(group);
    out.n_alpha = n_groups;
    out.rank    = npar - n_groups;
    out.Kmat    = Eigen::MatrixXd::Zero(npar, n_groups);
    for (std::int32_t k = 0; k < npar; ++k)
      out.Kmat(k, out.group[static_cast<std::size_t>(k)]) = 1.0;
    out.theta0  = Eigen::VectorXd::Zero(npar);

    // A_eq: one row per non-anchor member of each group, `e_first − e_k = 0`.
    // Iterate in k-order so anchor is the first appearance of each group id.
    out.A_eq = Eigen::MatrixXd::Zero(out.rank, npar);
    out.b_eq = Eigen::VectorXd::Zero(out.rank);
    std::vector<std::int32_t> first_of(static_cast<std::size_t>(n_groups), -1);
    Eigen::Index ai = 0;
    for (std::int32_t k = 0; k < npar; ++k) {
      const std::int32_t g = out.group[static_cast<std::size_t>(k)];
      auto& anchor = first_of[static_cast<std::size_t>(g)];
      if (anchor < 0) { anchor = k; continue; }
      out.A_eq(ai, anchor) = 1.0;
      out.A_eq(ai, k)      = -1.0;
      ++ai;
    }
    return out;
  }

  // ---- General-linear path: stack the merge rows + the lin_constraint rows. ----
  // Merge rows: for each group, anchor = its first member; for every other
  // member k, the row e_anchor − e_k (= 0).
  std::vector<std::int32_t> first_of(static_cast<std::size_t>(n_groups), -1);
  for (std::int32_t k = 0; k < npar; ++k) {
    const std::int32_t g = group[static_cast<std::size_t>(k)];
    if (first_of[static_cast<std::size_t>(g)] < 0) first_of[static_cast<std::size_t>(g)] = k;
  }
  const std::int32_t n_merge = npar - n_groups;
  const Eigen::Index m = static_cast<Eigen::Index>(n_merge) + static_cast<Eigen::Index>(n_lin);

  Eigen::MatrixXd R_full = Eigen::MatrixXd::Zero(m, npar);
  Eigen::VectorXd d_full = Eigen::VectorXd::Zero(m);
  Eigen::Index r_idx = 0;
  for (std::int32_t k = 0; k < npar; ++k) {
    const std::int32_t f = first_of[static_cast<std::size_t>(group[static_cast<std::size_t>(k)])];
    if (f == k) continue;
    R_full(r_idx, f) = 1.0;
    R_full(r_idx, k) = -1.0;
    ++r_idx;
  }
  for (std::size_t i = 0; i < n_lin; ++i) {
    for (std::int32_t c = 0; c < npar; ++c)
      R_full(r_idx, c) = pt.lin_constraint_R[i * P + static_cast<std::size_t>(c)];
    d_full(r_idx) = pt.lin_constraint_d[i];
    ++r_idx;
  }

  // Build the null-space basis per connected constraint component instead of
  // asking one global SVD for an arbitrary basis of the full kernel. The global
  // kernel is often degenerate: if loading constraints and intercept
  // constraints are independent, a global SVD may still rotate their free
  // directions together. The component-wise direct sum preserves the semantic
  // block structure while describing the same affine constraint surface.
  constexpr double support_tol = 1e-12;
  DisjointSet dsu(npar);
  std::vector<std::vector<std::int32_t>> row_support(static_cast<std::size_t>(m));
  for (Eigen::Index r = 0; r < m; ++r) {
    auto& supp = row_support[static_cast<std::size_t>(r)];
    for (std::int32_t c = 0; c < npar; ++c) {
      if (std::abs(R_full(r, c)) <= support_tol) continue;
      supp.push_back(c);
      if (supp.size() > 1) dsu.unite(supp.front(), c);
    }
  }

  std::unordered_map<std::int32_t, std::size_t> component_of_root;
  std::vector<ConstraintComponent> components;
  components.reserve(P);
  for (std::int32_t k = 0; k < npar; ++k) {
    const std::int32_t root = dsu.find(k);
    auto [it, inserted] =
        component_of_root.try_emplace(root, components.size());
    if (inserted) components.push_back({});
    components[it->second].params.push_back(k);
  }

  for (Eigen::Index r = 0; r < m; ++r) {
    const auto& supp = row_support[static_cast<std::size_t>(r)];
    if (supp.empty()) {
      Eigen::MatrixXd R_empty(1, 0);
      Eigen::VectorXd d_empty(1);
      d_empty(0) = d_full(r);
      const double resid = std::abs(d_full(r));
      if (resid > infeasibility_tolerance(R_empty, d_empty)) {
        return std::unexpected(err("infeasible linear-equality constraint system "
                                   "(residual " + std::to_string(resid) + ")"));
      }
      continue;
    }
    const std::int32_t root = dsu.find(supp.front());
    components[component_of_root[root]].rows.push_back(r);
  }

  std::vector<ComponentBasis> bases;
  bases.reserve(components.size());
  Eigen::Index total_alpha = 0;
  Eigen::Index total_rank = 0;
  double resid_sq = 0.0;

  for (const auto& comp : components) {
    ComponentBasis basis;
    basis.params = comp.params;
    const Eigen::Index pc = static_cast<Eigen::Index>(comp.params.size());
    const Eigen::Index mc = static_cast<Eigen::Index>(comp.rows.size());

    if (mc == 0) {
      basis.theta0 = Eigen::VectorXd::Zero(pc);
      basis.K = Eigen::MatrixXd::Identity(pc, pc);
      basis.A = Eigen::MatrixXd(0, pc);
      basis.b = Eigen::VectorXd::Zero(0);
      basis.n_alpha = pc;
      basis.rank = 0;
      total_alpha += basis.n_alpha;
      bases.push_back(std::move(basis));
      continue;
    }

    std::vector<std::int32_t> local_col(P, -1);
    for (Eigen::Index j = 0; j < pc; ++j) {
      local_col[static_cast<std::size_t>(comp.params[static_cast<std::size_t>(j)])] =
          static_cast<std::int32_t>(j);
    }

    Eigen::MatrixXd R_comp = Eigen::MatrixXd::Zero(mc, pc);
    Eigen::VectorXd d_comp(mc);
    for (Eigen::Index rr = 0; rr < mc; ++rr) {
      const Eigen::Index r_full = comp.rows[static_cast<std::size_t>(rr)];
      d_comp(rr) = d_full(r_full);
      for (std::int32_t c_full : row_support[static_cast<std::size_t>(r_full)]) {
        const std::int32_t c_local = local_col[static_cast<std::size_t>(c_full)];
        R_comp(rr, c_local) = R_full(r_full, c_full);
      }
    }

    Eigen::JacobiSVD<Eigen::MatrixXd> svd(
        R_comp, Eigen::ComputeFullU | Eigen::ComputeFullV);
    svd.setThreshold(1e-9);   // user constraint coefficients are O(1)-ish; this
                              // separates a genuine constraint from float noise.
    basis.rank = svd.rank();
    basis.n_alpha = pc - basis.rank;
    basis.theta0 = svd.solve(d_comp);                 // local min-norm solution
    const Eigen::VectorXd resid = R_comp * basis.theta0 - d_comp;
    resid_sq += resid.squaredNorm();
    if (resid.norm() > infeasibility_tolerance(R_comp, d_comp)) {
      return std::unexpected(err("infeasible linear-equality constraint system "
                                 "(residual " +
                                 std::to_string(std::sqrt(resid_sq)) + ")"));
    }
    basis.K = svd.matrixV().rightCols(basis.n_alpha);
    basis.A = svd.matrixV().leftCols(basis.rank).transpose();
    basis.b = basis.A * basis.theta0;

    total_alpha += basis.n_alpha;
    total_rank += basis.rank;
    bases.push_back(std::move(basis));
  }

  out.n_alpha = static_cast<std::int32_t>(total_alpha);
  out.rank    = static_cast<std::int32_t>(total_rank);
  out.Kmat    = Eigen::MatrixXd::Zero(npar, out.n_alpha);
  out.theta0  = Eigen::VectorXd::Zero(npar);
  out.A_eq    = Eigen::MatrixXd::Zero(out.rank, npar);
  out.b_eq    = Eigen::VectorXd::Zero(out.rank);
  // `group` left empty — the reparam is no longer a pure parameter merge.

  Eigen::Index alpha_off = 0;
  Eigen::Index rank_off = 0;
  for (const auto& basis : bases) {
    const Eigen::Index pc = static_cast<Eigen::Index>(basis.params.size());
    for (Eigen::Index j = 0; j < pc; ++j) {
      const std::int32_t p_full = basis.params[static_cast<std::size_t>(j)];
      out.theta0(p_full) = basis.theta0(j);
      if (basis.n_alpha > 0) {
        out.Kmat.block(p_full, alpha_off, 1, basis.n_alpha) =
            basis.K.block(j, 0, 1, basis.n_alpha);
      }
      if (basis.rank > 0) {
        out.A_eq.block(rank_off, p_full, basis.rank, 1) =
            basis.A.block(0, j, basis.rank, 1);
      }
    }
    if (basis.rank > 0) {
      out.b_eq.segment(rank_off, basis.rank) = basis.b;
    }
    alpha_off += basis.n_alpha;
    rank_off += basis.rank;
  }
  const double final_resid = (R_full * out.theta0 - d_full).norm();
  if (final_resid > infeasibility_tolerance(R_full, d_full)) {
    return std::unexpected(err("infeasible linear-equality constraint system "
                               "(residual " + std::to_string(final_resid) + ")"));
  }
  return out;
}

